/**
 * Order validators — pure validation functions for order operations.
 *
 * These are stateless, side-effect-free functions that validate
 * order-related inputs and state transitions.
 */

import type { OrderItem, OrderStatus } from '../models/order.js';

/**
 * Valid status transitions for orders.
 */
const STATUS_TRANSITIONS: Record<OrderStatus, OrderStatus[]> = {
  pending: ['confirmed', 'cancelled'],
  confirmed: ['shipped', 'cancelled'],
  shipped: ['delivered'],
  delivered: [],
  cancelled: [],
};

/**
 * Check whether a status transition is allowed.
 */
export function isValidStatusTransition(
  from: OrderStatus,
  to: OrderStatus,
): boolean {
  return STATUS_TRANSITIONS[from].includes(to);
}

/**
 * Validate that a status transition is allowed. Throws if not.
 */
export function validateStatusTransition(
  from: OrderStatus,
  to: OrderStatus,
): void {
  if (!isValidStatusTransition(from, to)) {
    throw new Error(`Invalid status transition: ${from} -> ${to}`);
  }
}

/**
 * Validate that an order has at least one item. Throws if empty.
 */
export function validateOrderItems(items: OrderItem[]): void {
  if (items.length === 0) {
    throw new Error('Order must have at least one item');
  }
}

/**
 * User validators — pure validation functions for user operations.
 *
 * These are stateless, side-effect-free functions that validate
 * user-related data. They receive already-fetched data as arguments
 * rather than performing any database lookups.
 */

import type { User } from '../models/user.js';

/**
 * Validate that a user exists. Throws if not found.
 * Returns the user as a typed value for convenience.
 */
export function validateUserExists(
  user: User | undefined,
  userId: string,
): User {
  if (!user) {
    throw new Error(`User not found: ${userId}`);
  }
  return user;
}

/**
 * Validate that an email is not already taken by another user. Throws if taken.
 */
export function validateEmailNotTaken(
  email: string,
  existingUser: User | undefined,
): void {
  if (existingUser) {
    throw new Error(`Email ${email} is already in use`);
  }
}

/**
 * Preferences validators — pure validation functions for user preferences.
 *
 * These are stateless, side-effect-free functions that validate
 * preferences-related data.
 */

import type { UserPreferences } from '../models/user-preferences.js';

/**
 * Validate that preferences do not already exist for a user. Throws if they do.
 */
export function validatePreferencesNotExist(
  existing: UserPreferences | undefined,
  userId: string,
): void {
  if (existing) {
    throw new Error(`Preferences already exist for user: ${userId}`);
  }
}

/**
 * Validate that preferences exist for a user. Throws if not found.
 * Returns the preferences for convenience.
 */
export function validatePreferencesExist(
  existing: UserPreferences | undefined,
  userId: string,
): UserPreferences {
  if (!existing) {
    throw new Error(`No preferences found for user: ${userId}`);
  }
  return existing;
}

