import { describe, it, expect } from 'vitest';
import {
  isValidStatusTransition,
  validateStatusTransition,
  validateOrderItems,
} from '../../src/validators/order.validator.js';

describe('Order Validators', () => {
  describe('isValidStatusTransition', () => {
    it('should allow pending -> confirmed', () => {
      expect(isValidStatusTransition('pending', 'confirmed')).toBe(true);
    });

    it('should allow pending -> cancelled', () => {
      expect(isValidStatusTransition('pending', 'cancelled')).toBe(true);
    });

    it('should allow confirmed -> shipped', () => {
      expect(isValidStatusTransition('confirmed', 'shipped')).toBe(true);
    });

    it('should allow confirmed -> cancelled', () => {
      expect(isValidStatusTransition('confirmed', 'cancelled')).toBe(true);
    });

    it('should allow shipped -> delivered', () => {
      expect(isValidStatusTransition('shipped', 'delivered')).toBe(true);
    });

    it('should reject pending -> delivered', () => {
      expect(isValidStatusTransition('pending', 'delivered')).toBe(false);
    });

    it('should reject delivered -> any', () => {
      expect(isValidStatusTransition('delivered', 'pending')).toBe(false);
      expect(isValidStatusTransition('delivered', 'cancelled')).toBe(false);
    });

    it('should reject cancelled -> any', () => {
      expect(isValidStatusTransition('cancelled', 'pending')).toBe(false);
      expect(isValidStatusTransition('cancelled', 'confirmed')).toBe(false);
    });
  });

  describe('validateStatusTransition', () => {
    it('should not throw for valid transitions', () => {
      expect(() => validateStatusTransition('pending', 'confirmed')).not.toThrow();
    });

    it('should throw for invalid transitions', () => {
      expect(() => validateStatusTransition('pending', 'delivered')).toThrow(
        'Invalid status transition: pending -> delivered',
      );
    });
  });

  describe('validateOrderItems', () => {
    it('should not throw for non-empty items', () => {
      expect(() =>
        validateOrderItems([
          { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
        ]),
      ).not.toThrow();
    });

    it('should throw for empty items', () => {
      expect(() => validateOrderItems([])).toThrow(
        'Order must have at least one item',
      );
    });
  });
});

import { describe, it, expect } from 'vitest';
import {
  validateUserExists,
  validateEmailAvailable,
  validateEmailNotTaken,
} from '../../src/validators/user.validator.js';
import type { User } from '../../src/models/user.js';

const mockUser: User = {
  id: 'user-0001',
  name: 'Alice',
  email: 'alice@example.com',
  role: 'member',
  createdAt: new Date(),
  updatedAt: new Date(),
};

describe('User Validators', () => {
  describe('validateUserExists', () => {
    it('should return the user when found', () => {
      const result = validateUserExists(mockUser, 'user-0001');
      expect(result).toBe(mockUser);
    });

    it('should throw when user is undefined', () => {
      expect(() => validateUserExists(undefined, 'user-9999')).toThrow(
        'User not found: user-9999',
      );
    });
  });

  describe('validateEmailAvailable', () => {
    it('should not throw when no existing user', () => {
      expect(() => validateEmailAvailable('new@example.com', undefined)).not.toThrow();
    });

    it('should throw when email is already taken', () => {
      expect(() => validateEmailAvailable('alice@example.com', mockUser)).toThrow(
        'User with email alice@example.com already exists',
      );
    });
  });

  describe('validateEmailNotTaken', () => {
    it('should not throw when no existing user', () => {
      expect(() => validateEmailNotTaken('new@example.com', undefined)).not.toThrow();
    });

    it('should throw when email is already in use', () => {
      expect(() => validateEmailNotTaken('alice@example.com', mockUser)).toThrow(
        'Email alice@example.com is already in use',
      );
    });
  });
});

import { describe, it, expect } from 'vitest';
import {
  validatePreferencesNotExist,
  validatePreferencesExist,
} from '../../src/validators/preferences.validator.js';
import type { UserPreferences } from '../../src/models/user-preferences.js';

const mockPrefs: UserPreferences = {
  id: 'pref-0001',
  userId: 'user-0001',
  email: {
    enabled: true,
    frequency: 'immediate',
    subscribedCategories: ['order_confirmation'],
  },
  createdAt: new Date(),
  updatedAt: new Date(),
};

describe('Preferences Validators', () => {
  describe('validatePreferencesNotExist', () => {
    it('should not throw when no existing preferences', () => {
      expect(() => validatePreferencesNotExist(undefined, 'user-0001')).not.toThrow();
    });

    it('should throw when preferences already exist', () => {
      expect(() => validatePreferencesNotExist(mockPrefs, 'user-0001')).toThrow(
        'Preferences already exist for user: user-0001',
      );
    });
  });

  describe('validatePreferencesExist', () => {
    it('should return preferences when found', () => {
      const result = validatePreferencesExist(mockPrefs, 'user-0001');
      expect(result).toBe(mockPrefs);
    });

    it('should throw when preferences not found', () => {
      expect(() => validatePreferencesExist(undefined, 'user-9999')).toThrow(
        'No preferences found for user: user-9999',
      );
    });
  });
});

